#include <stdio.h>
#include <string.h>
#include <stdbool.h>

#define LEN 78777
#define MAX 1000010
#define MOD 1000000007
#define clr(ar) memset(ar, 0, sizeof(ar))
#define read() freopen("lol.txt", "r", stdin)
#define chkbit(ar, i) (((ar[(i) >> 6]) & (1 << (((i) >> 1) & 31))))
#define setbit(ar, i) (((ar[(i) >> 6]) |= (1 << (((i) >> 1) & 31))))
#define isprime(x) (( (x) && ((x)&1) && (!chkbit(ar, (x)))) || ((x) == 2))

int p, x, y, prime[LEN];
unsigned int ar[(MAX >> 6) + 5] = {0};

void sieve(){
    int i, j, k;
    setbit(ar, 0), setbit(ar, 1);

    for (i = 3; (i * i) < MAX; i += 2){
        if (!chkbit(ar, i)){
            k = i << 1;
            for (j = (i * i); j < MAX; j += k) setbit(ar, j);
        }
    }

    p = 0;
    prime[p++] = 2;
    for (i = 3; i < MAX; i += 2){
        if (isprime(i)) prime[p++] = i;
    }
}

int expo(int a, int b){
    int res = 1;

    while (b){
        if (b & 1) res = (long long)res * a % MOD;
        a = (long long)a * a % MOD;
        b >>= 1;
    }
    return res;
}

int mobius(int n){
    if (n == 1) return 1;

    int i, j, x, counter = 0;
    for (i = 0; i < p; i++){
        if (prime[i] * prime[i] > n) break;
        for (j = 0; (n % prime[i]) == 0; j++, n /= prime[i]) {}
        if (j > 1) return 0;
        counter += (j == 1);
    }

    return (counter & 1) ? 1 : -1;
}

int count(int n, int d){
    return (mobius(d) * expo(2, (n / d) - 1) + MOD) % MOD;
}

int solve(int x, int y){
    int d, n, res = 0;
    if ((y % x) != 0) return 0;

    n = y / x;
    for (d = 1; d * d <= n; d++){
        if (n % d == 0){
            res = (res + count(n, d)) % MOD;
            if ((n / d) != d) res = (res + count(n, n / d)) % MOD;
        }
    }

    return res;
}

int main(){
    sieve();
    scanf("%d %d", &x, &y);
    printf("%d\n", solve(x, y));
    return 0;
}

