fn rec(m: u64, memo: &mut HashMap<u64, u64>) -> u64 {
    if let Some(&res) = memo.get(&m) {
        return res;
    }

    let mut s = mod_pow(2, m - 1, M);

    for x in (1..).take_while(|&x| x * x <= m) {
        if m % x == 0 {
            if x != 1 {
                s = (s + M - rec(m / x, memo)) % M;
            }
            if m / x != x {
                s = (s + M - rec(x, memo)) % M;
            }
        }
    }

    memo.insert(m, s);
    s
}

